/* ============================================================
   On-device OCR loader for Buy Later.

   This file makes the app work out of the box. By default it defines a
   minimal `Tesseract` object whose recognize() returns empty text, so the
   app simply asks you to type the details — with ZERO network calls.

   TO ENABLE REAL AUTO-FILL (still 100% offline):
   Replace this file with the official Tesseract.js build and drop the
   language data next to it. See INSTALL.txt step "Enable photo auto-scan".
   Because the app points Tesseract at local paths (tess/), the model and
   worker load from your device only — nothing is fetched from the internet.
   ============================================================ */

(function () {
  if (typeof window.Tesseract !== 'undefined') return; // real build present
  window.Tesseract = {
    recognize: function () {
      // No bundled model -> return empty result; user types fields manually.
      return Promise.resolve({ data: { text: '' } });
    }
  };
})();
